{
  "name": "OzonSight - Russian E-commerce Analyzer",
  "description": "AI-powered visual marketing expert for the Russian e-commerce market (Ozon, Wildberries). Upload product images to generate localized USPs, image prompts, and design blueprints."
}

export interface ProductInfo {
  category: string;
  identified_features: string[];
}

export interface SellingPoint {
  ru: string;
  zh: string;
}

export interface MarketUSPs {
  top_3_russian_selling_points: SellingPoint[];
}

export interface GeminiImagePrompts {
  main_image: string;
  lifestyle_scene: string;
}

export interface DesignBlueprint {
  recommended_ratio: string;
  text_overlay_plan: string;
  main_headline_ru: string;
}

export interface AnalysisResponse {
  product_info: ProductInfo;
  market_usps: MarketUSPs;
  gemini_image_prompts: GeminiImagePrompts;
  design_blueprint: DesignBlueprint;
}

export enum AppState {
  IDLE = 'IDLE',
  ANALYZING = 'ANALYZING',
  SUCCESS = 'SUCCESS',
  ERROR = 'ERROR'
}

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { AnalysisResponse } from "../types";

const SYSTEM_INSTRUCTION = `
Role: You are a world-class Visual Marketing Expert with 10 years of experience in the Russian e-commerce market (specifically Ozon and Wildberries). You specialize in analyzing cross-border products from China (e.g., apparel, electronics, home goods) and translating their features into high-conversion Russian marketing assets.

Objective: Analyze the uploaded product image and generate a structured JSON response containing:
1. Product identification.
2. Top 3 localized Russian Unique Selling Points (USPs) focusing on durability, warmth (if applicable), technical specs, and practicality.
3. Professional image generation prompts for main and lifestyle images.
4. A design blueprint for the infographic overlay.

Market Logic:
- Russian buyers are pragmatic; focus on quality and utility.
- Mention "Local Warehouse / Fast Delivery" implies the seller has local stock.
- Aesthetics: High contrast, clean shadows, "Techno-utilitarian" or "Cozy-durable".
- Colors: Ozon Blue (#005bff), Purple, or high-contrast warning colors.

Constraints:
- Do NOT include prices or contact info.
- Output MUST be valid JSON strictly adhering to the schema.
`;

// Define the schema for structured JSON output
const responseSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    product_info: {
      type: Type.OBJECT,
      properties: {
        category: { type: Type.STRING },
        identified_features: {
          type: Type.ARRAY,
          items: { type: Type.STRING },
        },
      },
      required: ["category", "identified_features"],
    },
    market_usps: {
      type: Type.OBJECT,
      properties: {
        top_3_russian_selling_points: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              ru: { type: Type.STRING },
              zh: { type: Type.STRING },
            },
            required: ["ru", "zh"],
          },
        },
      },
      required: ["top_3_russian_selling_points"],
    },
    gemini_image_prompts: {
      type: Type.OBJECT,
      properties: {
        main_image: { type: Type.STRING },
        lifestyle_scene: { type: Type.STRING },
      },
      required: ["main_image", "lifestyle_scene"],
    },
    design_blueprint: {
      type: Type.OBJECT,
      properties: {
        recommended_ratio: { type: Type.STRING },
        text_overlay_plan: { type: Type.STRING },
        main_headline_ru: { type: Type.STRING },
      },
      required: ["recommended_ratio", "text_overlay_plan", "main_headline_ru"],
    },
  },
  required: ["product_info", "market_usps", "gemini_image_prompts", "design_blueprint"],
};

export const analyzeProductImage = async (base64Image: string, mimeType: string): Promise<AnalysisResponse> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key is missing via process.env.API_KEY");
  }

  const ai = new GoogleGenAI({ apiKey });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview", // Using Flash for speed + multimodal capabilities
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: mimeType,
              data: base64Image,
            },
          },
          {
            text: "Analyze this product image for the Russian market (Ozon/Wildberries). Provide a JSON output.",
          },
        ],
      },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        temperature: 0.4, // Lower temperature for more consistent/professional output
      },
    });

    const text = response.text;
    if (!text) {
      throw new Error("No response text received from Gemini.");
    }

    return JSON.parse(text) as AnalysisResponse;
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    throw error;
  }
};

export const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const result = reader.result as string;
      // Remove the Data URL prefix (e.g., "data:image/jpeg;base64,")
      const base64 = result.split(",")[1];
      resolve(base64);
    };
    reader.onerror = (error) => reject(error);
  });
};

