import React, { useState, useRef } from 'react';
import { UploadCloud, Image as ImageIcon, X } from 'lucide-react';

interface ImageUploadProps {
  onImageSelect: (file: File) => void;
  selectedImage: File | null;
  onClear: () => void;
  isAnalyzing: boolean;
}

const ImageUpload: React.FC<ImageUploadProps> = ({ onImageSelect, selectedImage, onClear, isAnalyzing }) => {
  const [dragActive, setDragActive] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);

  const handleDrag = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === "dragenter" || e.type === "dragover") {
      setDragActive(true);
    } else if (e.type === "dragleave") {
      setDragActive(false);
    }
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      handleFile(e.dataTransfer.files[0]);
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    e.preventDefault();
    if (e.target.files && e.target.files[0]) {
      handleFile(e.target.files[0]);
    }
  };

  const handleFile = (file: File) => {
    if (!file.type.startsWith('image/')) {
      alert("Please upload an image file");
      return;
    }
    const url = URL.createObjectURL(file);
    setPreviewUrl(url);
    onImageSelect(file);
  };

  const clearImage = () => {
    if (previewUrl) {
      URL.revokeObjectURL(previewUrl);
    }
    setPreviewUrl(null);
    if (inputRef.current) inputRef.current.value = "";
    onClear();
  };

  const triggerClick = () => {
    inputRef.current?.click();
  };

  if (selectedImage && previewUrl) {
    return (
      <div className="w-full h-full min-h-[400px] flex flex-col relative rounded-2xl overflow-hidden bg-slate-100 border border-slate-200 shadow-sm group">
        <img 
          src={previewUrl} 
          alt="Product Preview" 
          className="w-full h-full object-contain p-4"
        />
        {!isAnalyzing && (
          <button 
            onClick={clearImage}
            className="absolute top-4 right-4 bg-white/90 backdrop-blur-sm hover:bg-red-50 text-slate-600 hover:text-red-600 p-2 rounded-full shadow-lg transition-all"
            title="Remove image"
          >
            <X size={20} />
          </button>
        )}
        {isAnalyzing && (
           <div className="absolute inset-0 bg-slate-900/20 backdrop-blur-[2px] flex items-center justify-center">
             <div className="bg-white px-6 py-3 rounded-full shadow-xl flex items-center gap-3">
               <div className="animate-spin rounded-full h-5 w-5 border-b-2 border-blue-600"></div>
               <span className="text-sm font-semibold text-slate-700">Analyzing Product...</span>
             </div>
           </div>
        )}
      </div>
    );
  }

  return (
    <div 
      className={`h-full min-h-[400px] flex flex-col items-center justify-center p-8 border-2 border-dashed rounded-2xl transition-all cursor-pointer bg-white
        ${dragActive ? "border-blue-500 bg-blue-50" : "border-slate-300 hover:border-blue-400 hover:bg-slate-50"}`}
      onDragEnter={handleDrag}
      onDragLeave={handleDrag}
      onDragOver={handleDrag}
      onDrop={handleDrop}
      onClick={triggerClick}
    >
      <input 
        ref={inputRef}
        type="file" 
        className="hidden" 
        onChange={handleChange}
        accept="image/*"
      />

      <div className="bg-blue-100 p-4 rounded-full text-blue-600 mb-4">
        <UploadCloud size={40} />
      </div>

      <h3 className="text-lg font-semibold text-slate-800 mb-2">Upload Product Image</h3>
      <p className="text-slate-500 text-center max-w-xs text-sm mb-6">
        Drag and drop your product photo here, or click to browse. Supports JPG, PNG, WEBP.
      </p>

      <div className="flex gap-4 text-xs text-slate-400">
        <div className="flex items-center gap-1">
          <ImageIcon size={14} />
          <span>High-Res Preferred</span>
        </div>
      </div>
    </div>
  );
};

export default ImageUpload;

