import { GoogleGenAI, Type, Schema } from "@google/genai";
import { AnalysisResponse } from "../types";

const SYSTEM_INSTRUCTION = `
Role: You are a world-class Visual Marketing Expert with 10 years of experience in the Russian e-commerce market (Ozon, Wildberries). You specialize in analyzing cross-border products (from China) using multiple angles/images to create high-conversion assets.

Objective: Analyze the provided product images and generate a structured JSON response.

REQUIREMENTS:

1.  **Product Identification**: Identify category and key features based on visual evidence.
2.  **Market USPs (Ozon/WB)**:
    *   Provide top 3 localized Russian Selling Points.
    *   Focus on: Durability, Thermal specs (if relevant), "Native" stock availability, Practicality.
    *   Tone: Pragmatic, "Techno-utilitarian", Trustworthy.
3.  **Gemini Image Prompts (EXACTLY 5 Types)**:
    *   You MUST generate 5 distinct prompts for specific marketing logic:
        1.  **Main Hero Shot**: Clean, high CTR, studio lighting, clear shadows.
        2.  **Infographic Base**: Angle with "Negative Space" specifically left for overlaying text.
        3.  **Lifestyle/Context**: The product in a real Russian usage scenario (e.g., snowy street, modern Moscow apartment).
        4.  **Detail/Texture**: Macro shot emphasizing material quality (stitching, fabric, metal finish).
        5.  **Technical/Scale**: A shot that helps visualize size, capacity, or internal structure.
4.  **Design Blueprint (Structured)**:
    *   Instead of a generic plan, provide a "Visual Hierarchy" list of elements (Headline, Subhead, Badge) to build the main infographic.

Constraints:
- Do NOT include prices.
- Output MUST be valid JSON strictly adhering to the schema.
`;

const responseSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    product_info: {
      type: Type.OBJECT,
      properties: {
        category: { type: Type.STRING },
        identified_features: { type: Type.ARRAY, items: { type: Type.STRING } },
      },
      required: ["category", "identified_features"],
    },
    market_usps: {
      type: Type.OBJECT,
      properties: {
        top_3_russian_selling_points: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              ru: { type: Type.STRING },
              zh: { type: Type.STRING },
            },
            required: ["ru", "zh"],
          },
        },
      },
      required: ["top_3_russian_selling_points"],
    },
    gemini_image_prompts: {
      type: Type.ARRAY,
      description: "Generate exactly 5 prompts: Hero, Infographic Base, Lifestyle, Detail, Technical.",
      items: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING, description: "e.g., Main Hero Shot" },
          purpose: { type: Type.STRING, description: "Why this image is needed" },
          prompt: { type: Type.STRING, description: "The English prompt for Imagen/Gemini" },
        },
        required: ["title", "purpose", "prompt"],
      },
    },
    design_blueprint: {
      type: Type.OBJECT,
      properties: {
        recommended_ratio: { type: Type.STRING },
        composition_advice: { type: Type.STRING },
        layout_structure: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              element_type: { type: Type.STRING, enum: ["Headline", "Subhead", "Badge", "FeatureList"] },
              text_content_ru: { type: Type.STRING },
              design_note: { type: Type.STRING },
              color_suggestion: { type: Type.STRING },
            },
            required: ["element_type", "text_content_ru", "design_note", "color_suggestion"],
          },
        },
      },
      required: ["recommended_ratio", "composition_advice", "layout_structure"],
    },
  },
  required: ["product_info", "market_usps", "gemini_image_prompts", "design_blueprint"],
};

export const analyzeProductImage = async (base64Images: string[], mimeTypes: string[]): Promise<AnalysisResponse> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key is missing via process.env.API_KEY");
  }

  const ai = new GoogleGenAI({ apiKey });

  // Construct parts: Multiple images followed by the text prompt
  const imageParts = base64Images.map((b64, index) => ({
    inlineData: {
      mimeType: mimeTypes[index],
      data: b64,
    },
  }));

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview", 
      contents: {
        parts: [
          ...imageParts,
          {
            text: "Analyze these product images for the Russian market (Ozon/Wildberries). Provide a comprehensive strategy JSON.",
          },
        ],
      },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        temperature: 0.4,
      },
    });

    const text = response.text;
    if (!text) {
      throw new Error("No response text received from Gemini.");
    }

    return JSON.parse(text) as AnalysisResponse;
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    throw error;
  }
};

export const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const result = reader.result as string;
      // Remove the Data URL prefix (e.g., "data:image/jpeg;base64,")
      const base64 = result.split(",")[1];
      resolve(base64);
    };
    reader.onerror = (error) => reject(error);
  });
};

import React, { useState, useRef, useEffect } from 'react';
import { UploadCloud, Image as ImageIcon, X, Plus } from 'lucide-react';

interface ImageUploadProps {
  onImagesSelect: (files: File[]) => void;
  selectedImages: File[];
  onClear: () => void;
  isAnalyzing: boolean;
}

const ImageUpload: React.FC<ImageUploadProps> = ({ onImagesSelect, selectedImages, onClear, isAnalyzing }) => {
  const [dragActive, setDragActive] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);
  const [previews, setPreviews] = useState<string[]>([]);

  // Generate previews when selectedImages changes
  useEffect(() => {
    const newPreviews = selectedImages.map(file => URL.createObjectURL(file));
    setPreviews(newPreviews);

    // Cleanup function to revoke URLs
    return () => {
      newPreviews.forEach(url => URL.revokeObjectURL(url));
    };
  }, [selectedImages]);

  const handleDrag = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === "dragenter" || e.type === "dragover") {
      setDragActive(true);
    } else if (e.type === "dragleave") {
      setDragActive(false);
    }
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
      handleFiles(Array.from(e.dataTransfer.files));
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    e.preventDefault();
    if (e.target.files && e.target.files.length > 0) {
      handleFiles(Array.from(e.target.files));
    }
  };

  const handleFiles = (newFiles: File[]) => {
    const validFiles = newFiles.filter(file => file.type.startsWith('image/'));
    if (validFiles.length === 0) {
      alert("Please upload image files");
      return;
    }
    // Combine with existing images, limit to e.g., 5 total if needed, but for now allow multiple
    onImagesSelect([...selectedImages, ...validFiles]);
  };

  const removeImage = (index: number) => {
    const newFiles = selectedImages.filter((_, i) => i !== index);
    onImagesSelect(newFiles);
    if (newFiles.length === 0) {
        onClear();
    }
  };

  const triggerClick = () => {
    inputRef.current?.click();
  };

  if (selectedImages.length > 0) {
    return (
      <div className="w-full relative rounded-2xl bg-slate-100 border border-slate-200 shadow-sm p-4">
        {isAnalyzing && (
           <div className="absolute inset-0 z-10 bg-slate-900/20 backdrop-blur-[2px] rounded-2xl flex items-center justify-center">
             <div className="bg-white px-6 py-3 rounded-full shadow-xl flex items-center gap-3">
               <div className="animate-spin rounded-full h-5 w-5 border-b-2 border-blue-600"></div>
               <span className="text-sm font-semibold text-slate-700">Analyzing {selectedImages.length} Image{selectedImages.length > 1 ? 's' : ''}...</span>
             </div>
           </div>
        )}

        <div className="grid grid-cols-2 md:grid-cols-3 gap-3">
            {previews.map((url, idx) => (
                <div key={idx} className="relative aspect-square bg-white rounded-xl border border-slate-200 overflow-hidden group">
                    <img src={url} alt={`preview ${idx}`} className="w-full h-full object-cover" />
                    {!isAnalyzing && (
                        <button 
                            onClick={(e) => { e.stopPropagation(); removeImage(idx); }}
                            className="absolute top-2 right-2 bg-white/90 text-slate-500 hover:text-red-500 p-1 rounded-full shadow-sm opacity-0 group-hover:opacity-100 transition-opacity"
                        >
                            <X size={16} />
                        </button>
                    )}
                </div>
            ))}

            {/* Add More Button */}
            {!isAnalyzing && (
                <button 
                    onClick={triggerClick}
                    className="aspect-square flex flex-col items-center justify-center bg-white border-2 border-dashed border-slate-300 rounded-xl hover:bg-slate-50 hover:border-blue-400 transition-all text-slate-400 hover:text-blue-500"
                >
                    <Plus size={24} />
                    <span className="text-xs font-medium mt-1">Add</span>
                </button>
            )}
        </div>

        {!isAnalyzing && (
             <div className="mt-4 flex justify-end">
                <button 
                    onClick={onClear}
                    className="text-xs text-red-500 font-medium hover:underline"
                >
                    Clear All
                </button>
             </div>
        )}

        <input 
            ref={inputRef}
            type="file" 
            className="hidden" 
            onChange={handleChange}
            accept="image/*"
            multiple 
        />
      </div>
    );
  }

  return (
    <div 
      className={`h-full min-h-[400px] flex flex-col items-center justify-center p-8 border-2 border-dashed rounded-2xl transition-all cursor-pointer bg-white
        ${dragActive ? "border-blue-500 bg-blue-50" : "border-slate-300 hover:border-blue-400 hover:bg-slate-50"}`}
      onDragEnter={handleDrag}
      onDragLeave={handleDrag}
      onDragOver={handleDrag}
      onDrop={handleDrop}
      onClick={triggerClick}
    >
      <input 
        ref={inputRef}
        type="file" 
        className="hidden" 
        onChange={handleChange}
        accept="image/*"
        multiple
      />

      <div className="bg-blue-100 p-4 rounded-full text-blue-600 mb-4">
        <UploadCloud size={40} />
      </div>

      <h3 className="text-lg font-semibold text-slate-800 mb-2">Upload Product Images</h3>
      <p className="text-slate-500 text-center max-w-xs text-sm mb-6">
        Drag and drop multiple photos (angles, details) for better analysis.
      </p>

      <div className="flex gap-4 text-xs text-slate-400">
        <div className="flex items-center gap-1">
          <ImageIcon size={14} />
          <span>Multi-file Supported</span>
        </div>
      </div>
    </div>
  );
};

