export const analyzeProductImage = async (base64Images: string[], mimeTypes: string[], userContext?: string): Promise<AnalysisResponse> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key is missing via process.env.API_KEY");
  }

  const ai = new GoogleGenAI({ apiKey });

  const imageParts = base64Images.map((b64, index) => ({
    inlineData: {
      mimeType: mimeTypes[index],
      data: b64,
    },
  }));

  let promptText = "Analyze these product images for the Russian market (Ozon/Wildberries). Provide a comprehensive strategy JSON.";
  if (userContext && userContext.trim().length > 0) {
    promptText += `\n\nCRITICAL USER CONTEXT (You MUST use this data for materials/specs in the output): "${userContext}"`;
  }

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview", 
      contents: {
        parts: [
          ...imageParts,
          { text: promptText },
        ],
      },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        temperature: 0.3, // Lower temperature for more adherence to user context
      },
    });

    const text = response.text;
    if (!text) {
      throw new Error("No response text received from Gemini.");
    }

    return JSON.parse(text) as AnalysisResponse;
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    throw error;
  }
};

export const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const result = reader.result as string;
      const base64 = result.split(",")[1];
      resolve(base64);
    };
    reader.onerror = (error) => reject(error);
  });
};

