import React, { useState, useRef, useEffect } from 'react';
import { UploadCloud, Image as ImageIcon, X, Plus } from 'lucide-react';

interface ImageUploadProps {
  onImagesSelect: (files: File[]) => void;
  selectedImages: File[];
  onClear: () => void;
  isAnalyzing: boolean;
}

const ImageUpload: React.FC<ImageUploadProps> = ({ onImagesSelect, selectedImages, onClear, isAnalyzing }) => {
  const [dragActive, setDragActive] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);
  const [previews, setPreviews] = useState<string[]>([]);

  // Generate previews when selectedImages changes
  useEffect(() => {
    const newPreviews = selectedImages.map(file => URL.createObjectURL(file));
    setPreviews(newPreviews);

    // Cleanup function to revoke URLs
    return () => {
      newPreviews.forEach(url => URL.revokeObjectURL(url));
    };
  }, [selectedImages]);

  const handleDrag = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === "dragenter" || e.type === "dragover") {
      setDragActive(true);
    } else if (e.type === "dragleave") {
      setDragActive(false);
    }
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
      handleFiles(Array.from(e.dataTransfer.files));
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    e.preventDefault();
    if (e.target.files && e.target.files.length > 0) {
      handleFiles(Array.from(e.target.files));
    }
  };

  const handleFiles = (newFiles: File[]) => {
    const validFiles = newFiles.filter(file => file.type.startsWith('image/'));
    if (validFiles.length === 0) {
      alert("请上传图片文件");
      return;
    }
    // Combine with existing images, limit to e.g., 5 total if needed, but for now allow multiple
    onImagesSelect([...selectedImages, ...validFiles]);
  };

  const removeImage = (index: number) => {
    const newFiles = selectedImages.filter((_, i) => i !== index);
    onImagesSelect(newFiles);
    if (newFiles.length === 0) {
        onClear();
    }
  };

  const triggerClick = () => {
    inputRef.current?.click();
  };

  if (selectedImages.length > 0) {
    return (
      <div className="w-full relative rounded-2xl bg-slate-100 border border-slate-200 shadow-sm p-4">
        {isAnalyzing && (
           <div className="absolute inset-0 z-10 bg-slate-900/20 backdrop-blur-[2px] rounded-2xl flex items-center justify-center">
             <div className="bg-white px-6 py-3 rounded-full shadow-xl flex items-center gap-3">
               <div className="animate-spin rounded-full h-5 w-5 border-b-2 border-blue-600"></div>
               <span className="text-sm font-semibold text-slate-700">正在分析 {selectedImages.length} 张图片...</span>
             </div>
           </div>
        )}

        <div className="grid grid-cols-2 md:grid-cols-3 gap-3">
            {previews.map((url, idx) => (
                <div key={idx} className="relative aspect-square bg-white rounded-xl border border-slate-200 overflow-hidden group">
                    <img src={url} alt={`preview ${idx}`} className="w-full h-full object-cover" />
                    {!isAnalyzing && (
                        <button 
                            onClick={(e) => { e.stopPropagation(); removeImage(idx); }}
                            className="absolute top-2 right-2 bg-white/90 text-slate-500 hover:text-red-500 p-1 rounded-full shadow-sm opacity-0 group-hover:opacity-100 transition-opacity"
                        >
                            <X size={16} />
                        </button>
                    )}
                </div>
            ))}

            {/* Add More Button */}
            {!isAnalyzing && (
                <button 
                    onClick={triggerClick}
                    className="aspect-square flex flex-col items-center justify-center bg-white border-2 border-dashed border-slate-300 rounded-xl hover:bg-slate-50 hover:border-blue-400 transition-all text-slate-400 hover:text-blue-500"
                >
                    <Plus size={24} />
                    <span className="text-xs font-medium mt-1">添加</span>
                </button>
            )}
        </div>

        {!isAnalyzing && (
             <div className="mt-4 flex justify-end">
                <button 
                    onClick={onClear}
                    className="text-xs text-red-500 font-medium hover:underline"
                >
                    清空全部
                </button>
             </div>
        )}

        <input 
            ref={inputRef}
            type="file" 
            className="hidden" 
            onChange={handleChange}
            accept="image/*"
            multiple 
        />
      </div>
    );
  }

  return (
    <div 
      className={`h-full min-h-[400px] flex flex-col items-center justify-center p-8 border-2 border-dashed rounded-2xl transition-all cursor-pointer bg-white
        ${dragActive ? "border-blue-500 bg-blue-50" : "border-slate-300 hover:border-blue-400 hover:bg-slate-50"}`}
      onDragEnter={handleDrag}
      onDragLeave={handleDrag}
      onDragOver={handleDrag}
      onDrop={handleDrop}
      onClick={triggerClick}
    >
      <input 
        ref={inputRef}
        type="file" 
        className="hidden" 
        onChange={handleChange}
        accept="image/*"
        multiple
      />

      <div className="bg-blue-100 p-4 rounded-full text-blue-600 mb-4">
        <UploadCloud size={40} />
      </div>

      <h3 className="text-lg font-semibold text-slate-800 mb-2">上传产品原图</h3>
      <p className="text-slate-500 text-center max-w-xs text-sm mb-6">
        拖拽或点击上传多张图片，支持不同角度与细节图。
      </p>

      <div className="flex gap-4 text-xs text-slate-400">
        <div className="flex items-center gap-1">
          <ImageIcon size={14} />
          <span>支持多文件上传</span>
        </div>
      </div>
    </div>
  );
};

