import { GoogleGenAI, Type, Schema } from "@google/genai";
import { AnalysisResponse, ImageStyle } from "../types";

const SYSTEM_INSTRUCTION = `
Role: You are a Tier-1 Visual Director for Russian E-commerce (Ozon, Wildberries).

Objective: Analyze product images + user context + selected visual style. 
Output a JSON with:
1.  **Product Info**: Category and features (in Chinese).
2.  **Market USPs**: Localized selling points for Russia (in Russian & Chinese).
3.  **Main Card Prompts (3:4)**: 5 prompts optimized for CTR on Ozon mobile feeds.
4.  **Rich Content Prompts (16:9)**: 5 prompts for "A+ Content" (Rich Content) storytelling banners.

---
### DYNAMIC PROMPT GENERATION LOGIC

Instead of using a static template, you must CONSTRUCT the prompt dynamically based on the **Product Category** and **Selected Style**.

**CORE RULES FOR ALL PROMPTS:**
1.  **Generative Fill Syntax**: MUST start with "Keep the product in the image unchanged, maintaining its original position and size."
2.  **Aspect Ratio**: 
    *   Main Card: \`--ar 3:4\`
    *   Rich Content: \`--ar 16:9\`
3.  **Realism**: NO generic "AI Art" styles. Use keywords like "Commercial Photography", "Phase One IQ4", "Raw Texture", "Depth of Field".
4.  **Localization**: Use Russian context where appropriate (e.g., "Moscow apartment interior", "Russian winter street", "Cyrillic packaging hints").

### STYLE GUIDELINES (Apply the selected style rigorously):

*   **Minimalist Studio (极简棚拍)**: 
    *   *Keywords*: Studio lighting, infinite background, softbox, high key, clean lines, geometric props.
    *   *Context*: Professional e-commerce studio.
*   **Outdoor Lifestyle (户外生活)**: 
    *   *Keywords*: Natural sunlight, bokeh, golden hour, street photography, park, urban texture.
    *   *Context*: Real world usage. For Russia: birch trees, panel buildings (background blur), snowy streets (if winter item).
*   **Cozy Home (温馨家居)**: 
    *   *Keywords*: Warm color temperature, fabric textures, interior design, soft shadows, lived-in feel.
    *   *Context*: Modern Russian apartment (Evroremont style), wooden floors, coffee table.
*   **Tech / Industrial (硬核科技)**: 
    *   *Keywords*: Rim light, neon accents (cyan/orange), dark background, metal textures, reflections, high contrast.
    *   *Context*: Gaming setup, workshop, dark room.
*   **Luxury / Premium (高端奢华)**: 
    *   *Keywords*: Low key, dramatic shadows, marble, velvet, gold accents, spot lighting.
    *   *Context*: Boutique hotel, expensive vanity, dark wood.

### PROMPT STRUCTURE REQUIREMENT:

**For Main Card (3:4):**
"Keep the product in the image unchanged, maintaining its original position and size. **Format: Vertical 3:4 Product Card.** [STYLE_SPECIFIC_SCENE]. Lighting: [STYLE_SPECIFIC_LIGHT]. Details: [TEXTURE_FOCUS]. **Russian Marketing Elements:** Composition allows space for top/bottom text. Visual hierarchy focuses on product. Render: Photorealistic, 8K."

**For Rich Content (16:9):**
"Keep the product in the image unchanged. **Format: Wide Landscape Banner.** [WIDER_STORYTELLING_SCENE]. Composition: [OFF_CENTER_COMPOSITION] with negative space for text on the right/left. Context: [STYLE_SPECIFIC_USAGE_SCENARIO]. Atmosphere: [EMOTIONAL_MOOD]. Render: High-end Editorial."

---

Constraints:
- Output valid JSON.
- **Prompts must be in English.**
- **NO CARTOON / NO ILLUSTRATION STYLES unless explicitly requested in context.**
`;

const responseSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    product_info: {
      type: Type.OBJECT,
      properties: {
        category: { type: Type.STRING, description: "Product category in Chinese" },
        identified_features: { type: Type.ARRAY, items: { type: Type.STRING }, description: "Key visual features in Chinese" },
      },
      required: ["category", "identified_features"],
    },
    market_usps: {
      type: Type.OBJECT,
      properties: {
        top_3_russian_selling_points: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              ru: { type: Type.STRING },
              zh: { type: Type.STRING },
            },
            required: ["ru", "zh"],
          },
        },
      },
      required: ["top_3_russian_selling_points"],
    },
    gemini_image_prompts: {
      type: Type.ARRAY,
      description: "Generate exactly 5 detailed prompts for the Main Product Card (Vertical 3:4).",
      items: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          purpose: { type: Type.STRING },
          prompt: { type: Type.STRING, description: "Prompt starting with 'Keep product unchanged... Format: Vertical 3:4...'" },
        },
        required: ["title", "purpose", "prompt"],
      },
    },
    gemini_rich_content_prompts: {
      type: Type.ARRAY,
      description: "Generate exactly 5 detailed prompts for Ozon Rich Content/A+ Banners (Landscape).",
      items: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          purpose: { type: Type.STRING },
          prompt: { type: Type.STRING, description: "Prompt starting with 'Keep product unchanged... Format: Wide Landscape...'" },
        },
        required: ["title", "purpose", "prompt"],
      },
    },
  },
  required: ["product_info", "market_usps", "gemini_image_prompts", "gemini_rich_content_prompts"],
};

export const analyzeProductImage = async (
  base64Images: string[], 
  mimeTypes: string[], 
  userContext: string,
  selectedStyle: ImageStyle
): Promise<AnalysisResponse> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key is missing via process.env.API_KEY");
  }

  const ai = new GoogleGenAI({ apiKey });

  const imageParts = base64Images.map((b64, index) => ({
    inlineData: {
      mimeType: mimeTypes[index],
      data: b64,
    },
  }));

  // Construct a dynamic prompt based on style
  let promptText = `Analyze these product images for the Russian market (Ozon/Wildberries). 

  **SELECTED VISUAL STYLE**: ${selectedStyle.toUpperCase()}

  Provide a comprehensive strategy JSON with:
  1. 5x Vertical (3:4) Prompts: Optimized for the selected style.
  2. 5x Horizontal (16:9) Prompts: Optimized for the selected style.

  Focus on PHOTOREALISM and RUSSIAN MARKET CONTEXT. Return metadata in Chinese.`;

  if (userContext && userContext.trim().length > 0) {
    promptText += `\n\nCRITICAL USER CONTEXT: "${userContext}"`;
  }

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview", 
      contents: {
        parts: [
          ...imageParts,
          { text: promptText },
        ],
      },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        temperature: 0.4, 
      },
    });

    const text = response.text;
    if (!text) {
      throw new Error("No response text received from Gemini.");
    }

    return JSON.parse(text) as AnalysisResponse;
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    throw error;
  }
};

export const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const result = reader.result as string;
      const base64 = result.split(",")[1];
      resolve(base64);
    };
    reader.onerror = (error) => reject(error);
  });
};

