export const analyzeProductImage = async (
  base64Images: string[], 
  mimeTypes: string[], 
  userContext: string,
  selectedStyle: ImageStyle
): Promise<AnalysisResponse> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key is missing via process.env.API_KEY");
  }

  const ai = new GoogleGenAI({ apiKey });

  const imageParts = base64Images.map((b64, index) => ({
    inlineData: {
      mimeType: mimeTypes[index],
      data: b64,
    },
  }));

  // Construct a dynamic prompt based on style
  let promptText = `Analyze these product images for the Russian market (Ozon/Wildberries). 

  **SELECTED VISUAL STYLE**: ${selectedStyle.toUpperCase()}

  Provide a comprehensive strategy JSON with:
  1. 5x Vertical (3:4) Prompts: Optimized for the selected style.
  2. 5x Horizontal (16:9) Prompts: Optimized for the selected style.

  Focus on PHOTOREALISM and RUSSIAN MARKET CONTEXT. 

  **CRITICAL LANGUAGE REQUIREMENT**:
  - The 'prompt' field MUST be in English.
  - The 'title', 'purpose', 'category', 'identified_features', and 'zh' fields MUST be in CHINESE (Simplified).
  - The 'ru' fields MUST be in Russian.`;

  if (userContext && userContext.trim().length > 0) {
    promptText += `\n\nCRITICAL USER CONTEXT: "${userContext}"`;
  }

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview", 
      contents: {
        parts: [
          ...imageParts,
          { text: promptText },
        ],
      },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        temperature: 0.4, 
      },
    });

    const text = response.text;
    if (!text) {
      throw new Error("No response text received from Gemini.");
    }

    return JSON.parse(text) as AnalysisResponse;
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    throw error;
  }
};

export const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const result = reader.result as string;
      const base64 = result.split(",")[1];
      resolve(base64);
    };
    reader.onerror = (error) => reject(error);
  });
};

