export const analyzeProductImage = async (
  base64Images: string[], 
  mimeTypes: string[], 
  userContext: string,
  selectedStyle: ImageStyle,
  customStyleDesc?: string
): Promise<AnalysisResponse> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key is missing via process.env.API_KEY");
  }

  const ai = new GoogleGenAI({ apiKey });

  const imageParts = base64Images.map((b64, index) => ({
    inlineData: {
      mimeType: mimeTypes[index],
      data: b64,
    },
  }));

  // Construct instruction based on style
  let styleInstruction = "";
  if (selectedStyle === 'auto') {
    styleInstruction = "AUTO_DETECT: Analyze the product aesthetics and category. Select the SINGLE Best visual style for the Russian market and apply it to all prompts. Explain the choice in 'recommended_visual_style'.";
  } else if (selectedStyle === 'custom') {
    styleInstruction = `CUSTOM USER STYLE: "${customStyleDesc || 'Use a style suitable for the product'}". Apply this specific user-defined visual style to all prompts.`;
  } else {
    styleInstruction = `SELECTED VISUAL STYLE: ${selectedStyle.toUpperCase()}. Apply this style strictly.`;
  }

  let promptText = `Analyze these product images for the Russian market (Ozon/Wildberries). 

  **STYLE STRATEGY**: ${styleInstruction}

  Provide a comprehensive strategy JSON with:
  1. 5x Vertical (3:4) Prompts.
  2. 5x Horizontal (16:9) Prompts.

  **IMPORTANT**: The 'prompt' content MUST be in **ENGLISH** but follow the strict "Visual Engineering" structure defined in System Instructions (e.g., "Keep the product... Construct a [SCENE]... Russian Marketing Visual Layout...").
  The 'title' and 'purpose' must be in **CHINESE**.`;

  if (userContext && userContext.trim().length > 0) {
    promptText += `\n\nCRITICAL USER CONTEXT: "${userContext}"`;
  }

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview", 
      contents: {
        parts: [
          ...imageParts,
          { text: promptText },
        ],
      },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        temperature: 0.4, 
      },
    });

    const text = response.text;
    if (!text) {
      throw new Error("No response text received from Gemini.");
    }

    return JSON.parse(text) as AnalysisResponse;
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    throw error;
  }
};

export const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const result = reader.result as string;
      const base64 = result.split(",")[1];
      resolve(base64);
    };
    reader.onerror = (error) => reject(error);
  });
};

import React, { useState } from 'react';
import Header from './components/Header';
import ImageUpload from './components/ImageUpload';
import ContextInput from './components/ContextInput';
import StyleSelector from './components/StyleSelector';
import AnalysisResult from './components/AnalysisResult';
import { analyzeProductImage, fileToBase64 } from './services/geminiService';
import { AnalysisResponse, AppState, ImageStyle } from './types';
import { AlertCircle, Sparkles, ArrowRight } from 'lucide-react';

const App: React.FC = () => {
  const [selectedFiles, setSelectedFiles] = useState<File[]>([]);
  const [contextText, setContextText] = useState<string>("");
  const [selectedStyle, setSelectedStyle] = useState<ImageStyle>('auto'); // Default to AUTO
  const [customStyleDesc, setCustomStyleDesc] = useState<string>(""); // New state for custom description
  const [appState, setAppState] = useState<AppState>(AppState.IDLE);
  const [analysisData, setAnalysisData] = useState<AnalysisResponse | null>(null);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  const handleImagesSelect = (files: File[]) => {
    setSelectedFiles(files);
    setAppState(AppState.IDLE);
    setAnalysisData(null);
    setErrorMsg(null);
  };

  const handleClear = () => {
    setSelectedFiles([]);
    setContextText("");
    setCustomStyleDesc("");
    setSelectedStyle('auto');
    setAppState(AppState.IDLE);
    setAnalysisData(null);
    setErrorMsg(null);
  };

  const startAnalysis = async () => {
    if (selectedFiles.length === 0) return;

    setAppState(AppState.ANALYZING);
    setErrorMsg(null);

    try {
      // Convert all files to base64
      const base64Promises = selectedFiles.map(file => fileToBase64(file));
      const base64Images = await Promise.all(base64Promises);
      const mimeTypes = selectedFiles.map(file => file.type);

      // Pass contextText, selectedStyle, and customStyleDesc to the service
      const result = await analyzeProductImage(
        base64Images, 
        mimeTypes, 
        contextText, 
        selectedStyle, 
        customStyleDesc
      );
      setAnalysisData(result);
      setAppState(AppState.SUCCESS);
    } catch (err: any) {
      console.error(err);
      setAppState(AppState.ERROR);
      setErrorMsg(err.message || "分析失败，请检查 API Key 或网络连接后重试。");
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 font-sans">
      <Header />

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

          {/* Left Column: Upload & Actions */}
          <div className="lg:col-span-5 space-y-6">
            <div className="bg-white p-1 rounded-2xl shadow-sm">
               <ImageUpload 
                  onImagesSelect={handleImagesSelect}
                  selectedImages={selectedFiles}
                  onClear={handleClear}
                  isAnalyzing={appState === AppState.ANALYZING}
               />
            </div>

            <StyleSelector 
                selectedStyle={selectedStyle}
                onSelect={setSelectedStyle}
                customStyleDesc={customStyleDesc}
                onCustomStyleChange={setCustomStyleDesc}
                disabled={appState === AppState.ANALYZING}
            />

            <ContextInput 
                value={contextText}
                onChange={setContextText}
                disabled={appState === AppState.ANALYZING}
            />

            {/* Action Area */}
            {selectedFiles.length > 0 && appState !== AppState.ANALYZING && appState !== AppState.SUCCESS && (
              <div className="animate-fade-in">
                <button
                  onClick={startAnalysis}
                  className="w-full bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-700 hover:to-indigo-700 text-white text-lg font-bold py-4 px-6 rounded-xl shadow-lg shadow-blue-500/30 flex items-center justify-center gap-2 transition-all transform hover:scale-[1.02]"
                >
                  <Sparkles size={20} className="text-yellow-300" />
                  一键生成 Ozon 视觉策略
                  <ArrowRight size={20} />
                </button>
              </div>
            )}

            {/* Loading State Text */}
            {appState === AppState.ANALYZING && (
              <div className="bg-blue-50 border border-blue-100 p-4 rounded-xl flex items-start gap-3">
                 <div className="mt-1 w-2 h-2 rounded-full bg-blue-500 animate-pulse"></div>
                 <div className="space-y-1">
                    <p className="text-sm font-semibold text-blue-800">视觉分析中...</p>
                    <p className="text-xs text-blue-600">
                        {selectedStyle === 'auto' 
                            ? "AI 正在分析产品特征并自动匹配最佳视觉风格..."
                            : selectedStyle === 'custom'
                                ? "正在根据您的自定义风格描述生成 Prompt..."
                                : "正在根据选择的风格解析图片并提取卖点..."}
                    </p>
                 </div>
              </div>
            )}

            {/* Error State */}
            {appState === AppState.ERROR && (
              <div className="bg-red-50 border border-red-100 p-4 rounded-xl flex items-start gap-3 text-red-700">
                <AlertCircle size={20} className="mt-0.5 flex-shrink-0" />
                <div>
                  <h4 className="font-semibold text-sm">分析失败</h4>
                  <p className="text-sm mt-1">{errorMsg}</p>
                  <button 
                    onClick={startAnalysis}
                    className="mt-3 text-xs font-bold bg-white border border-red-200 px-3 py-1.5 rounded-md hover:bg-red-50 transition-colors"
                  >
                    重试
                  </button>
                </div>
              </div>
            )}

            {/* Instructions / Tips (Only show when idle or analyzing) */}
            {appState !== AppState.SUCCESS && (
               <div className="bg-white rounded-xl shadow-sm p-6 border border-slate-200">
                  <h3 className="font-semibold text-slate-800 mb-3">操作指南</h3>
                  <ul className="space-y-3 text-sm text-slate-600">
                    <li className="flex gap-2">
                      <span className="bg-slate-100 text-slate-600 w-5 h-5 flex items-center justify-center rounded-full text-xs font-bold">1</span>
                      上传多张产品图片 (支持不同角度/细节)。
                    </li>
                    <li className="flex gap-2">
                      <span className="bg-slate-100 text-slate-600 w-5 h-5 flex items-center justify-center rounded-full text-xs font-bold">2</span>
                      选择 "AI 智能推荐" 或输入您的自定义风格。
                    </li>
                    <li className="flex gap-2">
                      <span className="bg-slate-100 text-slate-600 w-5 h-5 flex items-center justify-center rounded-full text-xs font-bold">3</span>
                      获取 5 组精准 Prompt 提示词与可视化方案。
                    </li>
                  </ul>
               </div>
            )}
          </div>

          {/* Right Column: Results */}
          <div className="lg:col-span-7">
            {appState === AppState.SUCCESS && analysisData ? (
              <AnalysisResult data={analysisData} />
            ) : (
              // Empty State Placeholder
              <div className="h-full min-h-[500px] flex flex-col items-center justify-center text-slate-300 border-2 border-dashed border-slate-200 rounded-2xl bg-white/50">
                 <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mb-4">
                    <Sparkles size={32} className="text-slate-300" />
                 </div>
                 <p className="font-medium text-slate-400">分析结果将在此处显示</p>
              </div>
            )}
          </div>

        </div>
      </main>
    </div>
  );
};

