import React, { useState, useRef, useEffect } from 'react';
import { UploadCloud, Image as ImageIcon, X, Plus } from 'lucide-react';

interface ImageUploadProps {
  onImagesSelect: (files: File[]) => void;
  selectedImages: File[];
  onClear: () => void;
  isAnalyzing: boolean;
}

const ImageUpload: React.FC<ImageUploadProps> = ({ onImagesSelect, selectedImages, onClear, isAnalyzing }) => {
  const [dragActive, setDragActive] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);
  const [previews, setPreviews] = useState<string[]>([]);

  // Generate previews when selectedImages changes
  useEffect(() => {
    const newPreviews = selectedImages.map(file => URL.createObjectURL(file));
    setPreviews(newPreviews);

    // Cleanup function to revoke URLs
    return () => {
      newPreviews.forEach(url => URL.revokeObjectURL(url));
    };
  }, [selectedImages]);

  const handleDrag = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === "dragenter" || e.type === "dragover") {
      setDragActive(true);
    } else if (e.type === "dragleave") {
      setDragActive(false);
    }
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
      handleFiles(Array.from(e.dataTransfer.files));
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    e.preventDefault();
    if (e.target.files && e.target.files.length > 0) {
      handleFiles(Array.from(e.target.files));
    }
  };

  const handleFiles = (newFiles: File[]) => {
    const validFiles = newFiles.filter(file => file.type.startsWith('image/'));
    if (validFiles.length === 0) {
      alert("请上传图片文件");
      return;
    }
    // Combine with existing images
    onImagesSelect([...selectedImages, ...validFiles]);
  };

  const removeImage = (index: number) => {
    const newFiles = selectedImages.filter((_, i) => i !== index);
    onImagesSelect(newFiles);
    if (newFiles.length === 0) {
        onClear();
    }
  };

  const triggerClick = () => {
    inputRef.current?.click();
  };

  if (selectedImages.length > 0) {
    return (
      <div className="w-full relative min-h-[200px] flex flex-col justify-between">
        {isAnalyzing && (
           <div className="absolute inset-0 z-20 bg-white/60 backdrop-blur-sm rounded-3xl flex items-center justify-center transition-all duration-500">
             {/* Loader is handled in App.tsx now, but we keep overlay to prevent interaction */}
           </div>
        )}

        <div className="grid grid-cols-2 sm:grid-cols-3 gap-3 p-2">
            {previews.map((url, idx) => (
                <div key={idx} className="group relative aspect-[3/4] rounded-2xl overflow-hidden shadow-sm hover:shadow-md transition-all duration-300 ring-1 ring-slate-900/5">
                    <img src={url} alt={`preview ${idx}`} className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110" />
                    <div className="absolute inset-0 bg-gradient-to-t from-black/50 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300"></div>
                    {!isAnalyzing && (
                        <button 
                            onClick={(e) => { e.stopPropagation(); removeImage(idx); }}
                            className="absolute top-2 right-2 bg-white text-slate-800 hover:bg-red-500 hover:text-white p-1.5 rounded-full shadow-lg opacity-0 group-hover:opacity-100 transition-all transform scale-90 group-hover:scale-100"
                        >
                            <X size={14} />
                        </button>
                    )}
                </div>
            ))}

            {/* Add More Button */}
            {!isAnalyzing && (
                <button 
                    onClick={triggerClick}
                    className="aspect-[3/4] flex flex-col items-center justify-center bg-slate-50 border border-dashed border-slate-300 rounded-2xl hover:bg-white hover:border-indigo-400 hover:shadow-md hover:shadow-indigo-100/50 transition-all group"
                >
                    <div className="bg-white p-3 rounded-full shadow-sm mb-2 group-hover:scale-110 transition-transform">
                        <Plus size={20} className="text-slate-400 group-hover:text-indigo-500" />
                    </div>
                    <span className="text-xs font-medium text-slate-500 group-hover:text-indigo-600">添加图片</span>
                </button>
            )}
        </div>

        {!isAnalyzing && (
             <div className="px-4 py-2 flex justify-between items-center border-t border-slate-100 mt-2">
                <span className="text-xs font-medium text-slate-500">{selectedImages.length} 张图片</span>
                <button 
                    onClick={onClear}
                    className="text-xs text-slate-400 font-medium hover:text-red-500 transition-colors px-2 py-1 rounded hover:bg-red-50"
                >
                    清空
                </button>
             </div>
        )}

        <input 
            ref={inputRef}
            type="file" 
            className="hidden" 
            onChange={handleChange}
            accept="image/*"
            multiple 
        />
      </div>
    );
  }

  return (
    <div 
      className={`relative h-full min-h-[320px] flex flex-col items-center justify-center p-8 border-2 border-dashed rounded-3xl transition-all duration-300 cursor-pointer overflow-hidden group
        ${dragActive 
            ? "border-indigo-500 bg-indigo-50/50 scale-[0.99]" 
            : "border-slate-200 hover:border-indigo-300 hover:bg-white/50 bg-slate-50/30"}`}
      onDragEnter={handleDrag}
      onDragLeave={handleDrag}
      onDragOver={handleDrag}
      onDrop={handleDrop}
      onClick={triggerClick}
    >
      <input 
        ref={inputRef}
        type="file" 
        className="hidden" 
        onChange={handleChange}
        accept="image/*"
        multiple
      />

      {/* Decorative background circle */}
      <div className="absolute bg-gradient-to-tr from-indigo-100 to-white w-48 h-48 rounded-full blur-2xl opacity-0 group-hover:opacity-60 transition-opacity duration-700 pointer-events-none"></div>

      <div className="relative z-10 flex flex-col items-center">
          <div className="bg-white p-5 rounded-2xl shadow-xl shadow-slate-200 mb-6 group-hover:scale-110 transition-transform duration-300 ring-1 ring-slate-100">
            <UploadCloud size={32} className="text-indigo-600" />
          </div>

          <h3 className="text-lg font-bold text-slate-800 mb-2 tracking-tight">上传产品原图</h3>
          <p className="text-slate-500 text-center max-w-xs text-sm mb-6 leading-relaxed">
            拖拽或点击上传，AI 将自动分析<br/>材质、结构与光影细节
          </p>

          <div className="flex items-center gap-2 px-3 py-1.5 bg-white/60 rounded-full border border-slate-200/60 shadow-sm">
            <ImageIcon size={14} className="text-slate-400" />
            <span className="text-xs font-semibold text-slate-500">支持批量上传</span>
          </div>
      </div>
    </div>
  );
};

