      <div className="bg-white/80 backdrop-blur-xl rounded-3xl shadow-xl shadow-slate-200/50 border border-white overflow-hidden">
        <div className="bg-gradient-to-r from-slate-50 to-white px-8 py-6 border-b border-slate-100 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-indigo-100 rounded-lg text-indigo-600">
                <Box size={20} />
            </div>
            <h2 className="font-bold text-slate-900 tracking-tight">Product Analysis</h2>
          </div>
          <span className="px-4 py-1.5 bg-slate-900 text-white text-xs font-bold uppercase rounded-full shadow-lg shadow-slate-500/20 tracking-wider">
              {data.product_info.category}
          </span>
        </div>
        <div className="p-8">
          {/* AI Style Recommendation */}
          <div className="mb-6 flex items-start gap-4 p-5 bg-gradient-to-br from-indigo-50 to-violet-50 rounded-2xl border border-indigo-100/50">
             <div className="p-2.5 bg-white rounded-xl shadow-sm text-indigo-500 shrink-0">
                <Sparkles size={20} />
             </div>
             <div>
                <p className="text-[10px] text-indigo-400 font-bold uppercase tracking-widest mb-1">Recommended Visual Strategy</p>
                <p className="text-lg font-bold text-indigo-950 leading-tight">{data.product_info.recommended_visual_style}</p>
             </div>
          </div>

          <div className="flex flex-wrap gap-2">
            {data.product_info.identified_features.map((feature, idx) => (
              <span key={idx} className="flex items-center gap-1.5 bg-white border border-slate-200 text-slate-600 px-3 py-1.5 rounded-lg text-xs font-semibold shadow-sm">
                <Tag size={12} className="text-slate-400" />
                {feature}
              </span>
            ))}
          </div>
        </div>
      </div>

      {/* 2. Russian Market USPs - Grid Layout */}
      <div>
        <div className="flex items-center gap-3 mb-4 px-2">
            <div className="p-2 bg-blue-600 rounded-lg text-white shadow-lg shadow-blue-500/30">
                <ShoppingCart size={18} />
            </div>
            <h2 className="text-xl font-bold text-slate-800 tracking-tight">Market USPs (RU/CN)</h2>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          {data.market_usps.top_3_russian_selling_points.map((usp, idx) => (
            <div key={idx} className="group relative bg-white rounded-2xl p-6 border border-slate-100 shadow-sm hover:shadow-xl hover:-translate-y-1 transition-all duration-300">
              <div className="absolute top-0 right-0 p-4 opacity-0 group-hover:opacity-100 transition-opacity">
                 <button 
                    onClick={() => handleCopy(usp.ru, `usp-${idx}`)}
                    className="text-slate-400 hover:text-blue-600 transition-colors"
                 >
                    {copiedSection === `usp-${idx}` ? <Check size={16} /> : <Copy size={16} />}
                 </button>
              </div>
              <div className="w-8 h-8 rounded-full bg-slate-100 text-slate-500 flex items-center justify-center font-bold text-sm mb-4 group-hover:bg-blue-600 group-hover:text-white transition-colors">
                {idx + 1}
