              <div className="space-y-2">
                <h3 className="text-lg font-bold text-slate-900 leading-snug">{usp.ru}</h3>
                <p className="text-xs text-slate-500 font-medium leading-relaxed border-t border-slate-100 pt-2 mt-2">
                    {usp.zh}
