      {/* 3. Main Product Card Images (3:4) */}
      <div className="space-y-5">
         <SectionHeader 
            icon={<Camera size={20} />}
            color="bg-slate-800"
            title="Main Card Prompts"
            subtitle="Format: 3:4 Vertical • High Conversion • Ozon/WB Style"
         />

         <div className="grid grid-cols-1 gap-6">
             {/* Main Hero Prompt */}
             {data.gemini_image_prompts.length > 0 && (
                <PromptCard 
                    key={0}
                    title={data.gemini_image_prompts[0].title}
                    purpose="HERO IMAGE (High Priority)"
