// --- Sub Components ---

const SectionHeader = ({icon, title, subtitle, color}: {icon: React.ReactNode, title: string, subtitle: string, color: string}) => (
    <div className="flex items-center justify-between px-2">
        <div className="flex items-center gap-3">
        <div className={`p-2.5 rounded-xl text-white shadow-lg ${color} shadow-${color.replace('bg-', '')}/30`}>
            {icon}
        </div>
        <div>
            <h2 className="text-xl font-bold text-slate-800 tracking-tight">{title}</h2>
            <p className="text-xs text-slate-500 font-medium mt-0.5">{subtitle}</p>
        </div>
        </div>
    </div>
)

interface PromptCardProps {
  title: string;
  purpose: string;
  prompt: string;
  onCopy: () => void;
  isCopied: boolean;
  index: number;
  isMain: boolean;
  aspect: '3:4' | 'landscape' | 'video';
}

const PromptCard: React.FC<PromptCardProps> = ({ title, purpose, prompt, onCopy, isCopied, index, isMain, aspect }) => {
  const accentColors = [
      'bg-blue-500', 
      'bg-indigo-500', 
      'bg-violet-500',
      'bg-purple-500',
      'bg-fuchsia-500'
  ];

  let accentColor = accentColors[index % accentColors.length];
  if (aspect === 'landscape') accentColor = 'bg-indigo-600';
  if (aspect === 'video') accentColor = 'bg-pink-600';

  return (
    <div className={`bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden flex flex-col transition-all duration-300 hover:shadow-xl hover:border-slate-200 group ${isMain ? 'ring-2 ring-indigo-50 shadow-md' : ''}`}>

        {/* Header */}
        <div className={`px-6 py-4 border-b border-slate-100 flex justify-between items-start ${isMain ? 'bg-slate-50/50' : 'bg-white'}`}>
            <div className="flex items-start gap-3">
                <div className={`w-1 h-8 rounded-full ${accentColor}`}></div>
                <div>
                    <h3 className="font-bold text-slate-800 text-sm">{title}</h3>
                    <div className="flex items-center gap-2 mt-1">
                        <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded text-white ${accentColor}`}>
                            {aspect === 'landscape' ? '16:9' : aspect === 'video' ? '9:16' : '3:4'}
                        </span>
                        <p className="text-xs text-slate-500 font-medium">{purpose}</p>
                    </div>
                </div>
            </div>
            <button 
                onClick={onCopy}
                className={`flex items-center gap-2 text-xs font-bold px-3 py-1.5 rounded-lg transition-all ${isCopied ? 'bg-green-50 text-green-600' : 'bg-slate-100 text-slate-600 hover:bg-slate-900 hover:text-white'}`}
            >
                {isCopied ? <Check size={14} /> : <Copy size={14} />}
                {isCopied ? 'COPIED' : 'COPY'}
            </button>
        </div>

        {/* Content */}
        <div className="p-6 bg-slate-50/30 flex-grow relative group-hover:bg-slate-50/80 transition-colors">
            <pre className="text-xs text-slate-600 leading-relaxed font-mono whitespace-pre-wrap font-medium">
                {prompt}
            </pre>
        </div>
    </div>
  );
};

export default AnalysisResult;

import React, { useState } from 'react';
import Header from './components/Header';
import ImageUpload from './components/ImageUpload';
import ContextInput from './components/ContextInput';
import StyleSelector from './components/StyleSelector';
import AnalysisResult from './components/AnalysisResult';
import { analyzeProductImage, fileToBase64 } from './services/geminiService';
import { AnalysisResponse, AppState, ImageStyle } from './types';
import { AlertCircle, Sparkles, ArrowRight, Loader2 } from 'lucide-react';

const App: React.FC = () => {
  const [selectedFiles, setSelectedFiles] = useState<File[]>([]);
  const [contextText, setContextText] = useState<string>("");
  const [selectedStyle, setSelectedStyle] = useState<ImageStyle>('auto'); // Default to AUTO
  const [customStyleDesc, setCustomStyleDesc] = useState<string>(""); // New state for custom description
  const [appState, setAppState] = useState<AppState>(AppState.IDLE);
  const [analysisData, setAnalysisData] = useState<AnalysisResponse | null>(null);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  const handleImagesSelect = (files: File[]) => {
    setSelectedFiles(files);
    setAppState(AppState.IDLE);
    setAnalysisData(null);
    setErrorMsg(null);
  };

  const handleClear = () => {
    setSelectedFiles([]);
    setContextText("");
    setCustomStyleDesc("");
    setSelectedStyle('auto');
    setAppState(AppState.IDLE);
    setAnalysisData(null);
    setErrorMsg(null);
  };

  const startAnalysis = async () => {
    if (selectedFiles.length === 0) return;

    setAppState(AppState.ANALYZING);
    setErrorMsg(null);

    try {
      // Convert all files to base64
      const base64Promises = selectedFiles.map(file => fileToBase64(file));
      const base64Images = await Promise.all(base64Promises);
      const mimeTypes = selectedFiles.map(file => file.type);

      // Pass contextText, selectedStyle, and customStyleDesc to the service
      const result = await analyzeProductImage(
        base64Images, 
        mimeTypes, 
        contextText, 
        selectedStyle, 
        customStyleDesc
      );
      setAnalysisData(result);
      setAppState(AppState.SUCCESS);
    } catch (err: any) {
      console.error(err);
      setAppState(AppState.ERROR);
      setErrorMsg(err.message || "分析失败，请检查 API Key 或网络连接后重试。");
    }
  };

  return (
    <div className="min-h-screen bg-slate-100 text-slate-900 font-sans relative selection:bg-indigo-100 selection:text-indigo-900">
      {/* Ambient Background Elements - Reduced Opacity for less glare */}
      <div className="fixed inset-0 z-0 pointer-events-none overflow-hidden">
        <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] rounded-full bg-blue-200/30 blur-[120px] mix-blend-multiply opacity-50 animate-blob"></div>
        <div className="absolute top-[10%] right-[-10%] w-[40%] h-[40%] rounded-full bg-indigo-200/30 blur-[120px] mix-blend-multiply opacity-50 animate-blob animation-delay-2000"></div>
        <div className="absolute bottom-[-10%] left-[20%] w-[40%] h-[40%] rounded-full bg-violet-200/30 blur-[120px] mix-blend-multiply opacity-50 animate-blob animation-delay-4000"></div>
        <div className="absolute inset-0 bg-grid-slate-200 [mask-image:linear-gradient(0deg,white,rgba(255,255,255,0.5))]"></div>
      </div>

      <Header />

      <main className="relative z-10 max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10">

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">

          {/* Left Column: Upload & Actions - Sticky on large screens */}
          <div className="lg:col-span-5 space-y-6 lg:sticky lg:top-24 transition-all duration-300">
            {/* Image Upload Card - Solid White for contrast */}
            <div className="bg-white border border-slate-200 p-1 rounded-3xl shadow-sm">
               <ImageUpload 
                  onImagesSelect={handleImagesSelect}
                  selectedImages={selectedFiles}
                  onClear={handleClear}
                  isAnalyzing={appState === AppState.ANALYZING}
               />
            </div>

            <StyleSelector 
                selectedStyle={selectedStyle}
                onSelect={setSelectedStyle}
                customStyleDesc={customStyleDesc}
                onCustomStyleChange={setCustomStyleDesc}
                disabled={appState === AppState.ANALYZING}
            />

            <ContextInput 
                value={contextText}
                onChange={setContextText}
                disabled={appState === AppState.ANALYZING}
            />

            {/* Action Area */}
            {selectedFiles.length > 0 && appState !== AppState.ANALYZING && appState !== AppState.SUCCESS && (
              <div className="animate-fade-in pt-2">
                <button
                  onClick={startAnalysis}
                  className="group w-full relative overflow-hidden bg-slate-900 hover:bg-black text-white text-lg font-medium py-4 px-6 rounded-2xl shadow-xl shadow-slate-900/20 transition-all transform hover:scale-[1.01] active:scale-[0.99]"
                >
                   <div className="absolute inset-0 w-full h-full bg-gradient-to-r from-transparent via-white/10 to-transparent translate-x-[-100%] group-hover:translate-x-[100%] transition-transform duration-1000"></div>
                   <div className="relative flex items-center justify-center gap-3">
                      <Sparkles size={20} className="text-indigo-400" />
                      <span>Generate Visual Strategy</span>
                      <ArrowRight size={20} className="opacity-70 group-hover:opacity-100 group-hover:translate-x-1 transition-all" />
                   </div>
                </button>
              </div>
            )}

            {/* Loading State */}
            {appState === AppState.ANALYZING && (
              <div className="bg-white border border-indigo-100 p-6 rounded-2xl shadow-lg shadow-indigo-100/50 flex items-start gap-4">
                 <div className="relative">
                    <div className="absolute inset-0 bg-indigo-500 rounded-full animate-ping opacity-20"></div>
                    <div className="relative bg-indigo-50 text-indigo-600 p-2 rounded-full">
                        <Loader2 size={24} className="animate-spin" />
                    </div>
                 </div>
                 <div className="space-y-1">
                    <h4 className="font-bold text-slate-800">正在进行视觉工程分析</h4>
                    <p className="text-sm text-slate-500 leading-relaxed">
                        {selectedStyle === 'auto' 
                            ? "AI 正在解构产品材质、光影结构，并匹配俄罗斯市场最佳审美风格..."
                            : selectedStyle === 'custom'
                                ? "正在解析您的自定义风格指令，构建专属视觉方案..."
                                : `正在应用 ${selectedStyle} 风格模型，生成高转化率视觉方案...`}
                    </p>
                 </div>
              </div>
            )}

            {/* Error State */}
            {appState === AppState.ERROR && (
              <div className="bg-white border border-red-200 p-5 rounded-2xl flex items-start gap-3 text-red-700 shadow-sm">
                <AlertCircle size={20} className="mt-0.5 flex-shrink-0" />
                <div>
                  <h4 className="font-semibold text-sm">分析中断</h4>
                  <p className="text-sm mt-1 opacity-90">{errorMsg}</p>
                  <button 
                    onClick={startAnalysis}
                    className="mt-3 text-xs font-bold bg-white border border-red-200 px-4 py-2 rounded-lg hover:bg-red-50 transition-colors shadow-sm text-red-600"
                  >
                    重试
                  </button>
                </div>
              </div>
            )}

            {/* Instructions / Tips - Darker text */}
            {appState !== AppState.SUCCESS && (
               <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
                  <h3 className="font-semibold text-slate-800 mb-4 text-xs uppercase tracking-wider opacity-70">Workflow</h3>
                  <ul className="space-y-4">
                    <StepItem number="01" text="上传产品原图 (支持多角度)" />
                    <StepItem number="02" text="选择视觉风格 (AI推荐或自定义)" />
                    <StepItem number="03" text="获取全套本土化视觉方案" />
                  </ul>
               </div>
            )}
          </div>

          {/* Right Column: Results */}
          <div className="lg:col-span-7 transition-all duration-500 ease-in-out">
            {appState === AppState.SUCCESS && analysisData ? (
              <AnalysisResult data={analysisData} />
            ) : (
              // Empty State Placeholder
              <div className="h-full min-h-[600px] flex flex-col items-center justify-center text-slate-400 border-2 border-dashed border-slate-300 rounded-3xl bg-slate-50/50">
                 <div className="w-24 h-24 bg-white rounded-full shadow-sm border border-slate-100 flex items-center justify-center mb-6">
                    <Sparkles size={32} className="text-slate-300" />
                 </div>
                 <h3 className="text-lg font-semibold text-slate-600">等待视觉分析</h3>
                 <p className="text-sm text-slate-500 mt-2">分析结果将在此处生成预览</p>
              </div>
            )}
          </div>

        </div>
      </main>
    </div>
  );
};

const StepItem = ({number, text}: {number: string, text: string}) => (
    <li className="flex gap-4 items-center group">
        <span className="font-mono text-xs font-bold text-indigo-500 bg-indigo-50 border border-indigo-100 px-2 py-1 rounded-md group-hover:bg-indigo-100 transition-colors">
            {number}
        </span>
        <span className="text-sm text-slate-700 font-medium">{text}</span>
    </li>
);

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { UploadCloud, Image as ImageIcon, X, Plus } from 'lucide-react';

interface ImageUploadProps {
  onImagesSelect: (files: File[]) => void;
  selectedImages: File[];
  onClear: () => void;
  isAnalyzing: boolean;
}

const ImageUpload: React.FC<ImageUploadProps> = ({ onImagesSelect, selectedImages, onClear, isAnalyzing }) => {
  const [dragActive, setDragActive] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);
  const [previews, setPreviews] = useState<string[]>([]);

  // Generate previews when selectedImages changes
  useEffect(() => {
    const newPreviews = selectedImages.map(file => URL.createObjectURL(file));
    setPreviews(newPreviews);

    // Cleanup function to revoke URLs
    return () => {
      newPreviews.forEach(url => URL.revokeObjectURL(url));
    };
  }, [selectedImages]);

  const handleDrag = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === "dragenter" || e.type === "dragover") {
      setDragActive(true);
    } else if (e.type === "dragleave") {
      setDragActive(false);
    }
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
      handleFiles(Array.from(e.dataTransfer.files));
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    e.preventDefault();
    if (e.target.files && e.target.files.length > 0) {
      handleFiles(Array.from(e.target.files));
    }
  };

  const handleFiles = (newFiles: File[]) => {
    const validFiles = newFiles.filter(file => file.type.startsWith('image/'));
    if (validFiles.length === 0) {
      alert("请上传图片文件");
      return;
    }
    // Combine with existing images
    onImagesSelect([...selectedImages, ...validFiles]);
  };

  const removeImage = (index: number) => {
    const newFiles = selectedImages.filter((_, i) => i !== index);
    onImagesSelect(newFiles);
    if (newFiles.length === 0) {
        onClear();
    }
  };

  const triggerClick = () => {
    inputRef.current?.click();
  };

  if (selectedImages.length > 0) {
    return (
      <div className="w-full relative min-h-[200px] flex flex-col justify-between">
        {isAnalyzing && (
           <div className="absolute inset-0 z-20 bg-white/60 backdrop-blur-sm rounded-3xl flex items-center justify-center transition-all duration-500">
             {/* Loader is handled in App.tsx */}
           </div>
        )}

        <div className="grid grid-cols-2 sm:grid-cols-3 gap-3 p-3">
            {previews.map((url, idx) => (
                <div key={idx} className="group relative aspect-[3/4] rounded-2xl overflow-hidden shadow-sm hover:shadow-md transition-all duration-300 ring-1 ring-slate-200">
                    <img src={url} alt={`preview ${idx}`} className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110" />
                    <div className="absolute inset-0 bg-gradient-to-t from-black/50 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300"></div>
                    {!isAnalyzing && (
                        <button 
                            onClick={(e) => { e.stopPropagation(); removeImage(idx); }}
                            className="absolute top-2 right-2 bg-white text-slate-800 hover:bg-red-500 hover:text-white p-1.5 rounded-full shadow-lg opacity-0 group-hover:opacity-100 transition-all transform scale-90 group-hover:scale-100"
                        >
                            <X size={14} />
                        </button>
                    )}
                </div>
            ))}

            {/* Add More Button */}
            {!isAnalyzing && (
                <button 
                    onClick={triggerClick}
                    className="aspect-[3/4] flex flex-col items-center justify-center bg-slate-50 border border-dashed border-slate-300 rounded-2xl hover:bg-white hover:border-indigo-400 hover:shadow-md hover:shadow-indigo-100/50 transition-all group"
                >
                    <div className="bg-white p-3 rounded-full shadow-sm mb-2 group-hover:scale-110 transition-transform border border-slate-200">
                        <Plus size={20} className="text-slate-400 group-hover:text-indigo-500" />
                    </div>
                    <span className="text-xs font-medium text-slate-500 group-hover:text-indigo-600">添加图片</span>
