            accept="image/*"
            multiple 
        />
      </div>
    );
  }

  return (
    <div 
      className={`relative h-full min-h-[320px] flex flex-col items-center justify-center p-8 border-2 border-dashed rounded-3xl transition-all duration-300 cursor-pointer overflow-hidden group
        ${dragActive 
