interface PromptCardProps {
  title: string;
  purpose: string;
  prompt: string;
  onCopy: () => void;
  isCopied: boolean;
  index: number;
  isMain: boolean;
  aspect: '3:4' | 'landscape' | 'video';
}

const PromptCard: React.FC<PromptCardProps> = ({ title, purpose, prompt, onCopy, isCopied, index, isMain, aspect }) => {
  const accentColors = [
      'bg-blue-500', 
      'bg-indigo-500', 
      'bg-violet-500',
      'bg-purple-500',
      'bg-fuchsia-500'
  ];

  let accentColor = accentColors[index % accentColors.length];
  if (aspect === 'landscape') accentColor = 'bg-indigo-600';
  if (aspect === 'video') accentColor = 'bg-pink-600';

  return (
    <div className={`bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden flex flex-col transition-all duration-300 hover:shadow-lg hover:border-slate-300 group ${isMain ? 'ring-2 ring-indigo-50 shadow-md' : ''}`}>

        {/* Header */}
        <div className={`px-6 py-4 border-b border-slate-100 flex justify-between items-start ${isMain ? 'bg-slate-50' : 'bg-white'}`}>
            <div className="flex items-start gap-3">
                <div className={`w-1 h-8 rounded-full ${accentColor}`}></div>
                <div>
                    <h3 className="font-bold text-slate-800 text-sm">{title}</h3>
                    <div className="flex items-center gap-2 mt-1">
                        <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded text-white ${accentColor}`}>
                            {aspect === 'landscape' ? '16:9' : aspect === 'video' ? '9:16' : '3:4'}
                        </span>
                        <p className="text-xs text-slate-500 font-medium">{purpose}</p>
                    </div>
                </div>
            </div>
            <button 
                onClick={onCopy}
                className={`flex items-center gap-2 text-xs font-bold px-3 py-1.5 rounded-lg transition-all ${isCopied ? 'bg-green-100 text-green-700' : 'bg-slate-100 text-slate-600 hover:bg-slate-900 hover:text-white'}`}
            >
                {isCopied ? <Check size={14} /> : <Copy size={14} />}
                {isCopied ? 'COPIED' : 'COPY'}
            </button>
        </div>

        {/* Content */}
        <div className="p-6 bg-slate-50/50 flex-grow relative group-hover:bg-slate-50 transition-colors">
            <pre className="text-xs text-slate-700 leading-relaxed font-mono whitespace-pre-wrap font-medium">
                {prompt}
            </pre>
        </div>
    </div>
  );
};

