import React, { useState } from 'react';
import Header from './components/Header';
import ImageUpload from './components/ImageUpload';
import ContextInput from './components/ContextInput';
import StyleSelector from './components/StyleSelector';
import AnalysisResult from './components/AnalysisResult';
import { analyzeProductImage, fileToBase64 } from './services/geminiService';
import { AnalysisResponse, AppState, ImageStyle } from './types';
import { AlertCircle, Sparkles, ArrowRight, Loader2, Zap, Globe } from 'lucide-react';

const App: React.FC = () => {
  const [selectedFiles, setSelectedFiles] = useState<File[]>([]);
  const [contextText, setContextText] = useState<string>("");
  const [selectedStyle, setSelectedStyle] = useState<ImageStyle>('auto');
  const [customStyleDesc, setCustomStyleDesc] = useState<string>("");
  const [appState, setAppState] = useState<AppState>(AppState.IDLE);
  const [analysisData, setAnalysisData] = useState<AnalysisResponse | null>(null);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  const handleImagesSelect = (files: File[]) => {
    setSelectedFiles(files);
    setAppState(AppState.IDLE);
    setAnalysisData(null);
    setErrorMsg(null);
  };

  const handleClear = () => {
    setSelectedFiles([]);
    setContextText("");
    setCustomStyleDesc("");
    setSelectedStyle('auto');
    setAppState(AppState.IDLE);
    setAnalysisData(null);
    setErrorMsg(null);
  };

  const startAnalysis = async () => {
    if (selectedFiles.length === 0) return;

    setAppState(AppState.ANALYZING);
    setErrorMsg(null);

    try {
      const base64Promises = selectedFiles.map(file => fileToBase64(file));
      const base64Images = await Promise.all(base64Promises);
      const mimeTypes = selectedFiles.map(file => file.type);

      const result = await analyzeProductImage(
        base64Images, 
        mimeTypes, 
        contextText, 
        selectedStyle, 
        customStyleDesc
      );
      setAnalysisData(result);
      setAppState(AppState.SUCCESS);
    } catch (err: any) {
      console.error(err);
      setAppState(AppState.ERROR);
      setErrorMsg(err.message || "分析失败，请检查 API Key 或网络连接后重试。");
    }
  };

  return (
    <div className="flex flex-col lg:flex-row h-screen bg-slate-50 overflow-hidden text-slate-900">

      {/* === LEFT SIDEBAR: CONTROLS === */}
      <aside className="w-full lg:w-[440px] bg-white border-r border-slate-200 flex flex-col shrink-0 z-30 shadow-xl shadow-slate-200/50">

        {/* Sidebar Header */}
        <div className="p-6 border-b border-slate-100 flex-shrink-0 bg-white z-10">
           <Header />
        </div>

        {/* Scrollable Inputs */}
        <div className="flex-1 overflow-y-auto custom-scrollbar p-6 space-y-8">

           <div className="space-y-4">
              <SectionLabel title="01. Product Source" />
              <ImageUpload 
                  onImagesSelect={handleImagesSelect}
                  selectedImages={selectedFiles}
                  onClear={handleClear}
                  isAnalyzing={appState === AppState.ANALYZING}
               />
           </div>

           <div className="space-y-4">
              <SectionLabel title="02. Visual Strategy" />
              <StyleSelector 
                  selectedStyle={selectedStyle}
                  onSelect={setSelectedStyle}
                  customStyleDesc={customStyleDesc}
                  onCustomStyleChange={setCustomStyleDesc}
                  disabled={appState === AppState.ANALYZING}
              />
           </div>

           <div className="space-y-4">
              <SectionLabel title="03. Context (Optional)" />
              <ContextInput 
                  value={contextText}
                  onChange={setContextText}
                  disabled={appState === AppState.ANALYZING}
              />
           </div>
        </div>

        {/* Fixed Footer Action Area */}
        <div className="p-6 border-t border-slate-100 bg-white flex-shrink-0 z-10">
            {appState === AppState.ERROR && (
               <div className="mb-4 bg-red-50 border border-red-100 p-3 rounded-xl flex items-start gap-3 text-red-700 text-sm">
                 <AlertCircle size={18} className="mt-0.5 flex-shrink-0" />
                 <div>{errorMsg}</div>
               </div>
            )}

            <button
              onClick={startAnalysis}
              disabled={selectedFiles.length === 0 || appState === AppState.ANALYZING}
              className={`
                 group w-full relative overflow-hidden text-lg font-medium py-4 px-6 rounded-xl shadow-lg transition-all transform
                 ${selectedFiles.length === 0 || appState === AppState.ANALYZING 
                    ? 'bg-slate-100 text-slate-400 cursor-not-allowed shadow-none' 
                    : 'bg-slate-900 hover:bg-black text-white hover:scale-[1.01] active:scale-[0.99] shadow-indigo-900/20'}
