import React, { useState, useRef, useEffect } from 'react';
import { UploadCloud, Image as ImageIcon, X, Plus } from 'lucide-react';

interface ImageUploadProps {
  onImagesSelect: (files: File[]) => void;
  selectedImages: File[];
  onClear: () => void;
  isAnalyzing: boolean;
}

const ImageUpload: React.FC<ImageUploadProps> = ({ onImagesSelect, selectedImages, onClear, isAnalyzing }) => {
  const [dragActive, setDragActive] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);
  const [previews, setPreviews] = useState<string[]>([]);

  useEffect(() => {
    const newPreviews = selectedImages.map(file => URL.createObjectURL(file));
    setPreviews(newPreviews);
    return () => {
      newPreviews.forEach(url => URL.revokeObjectURL(url));
    };
  }, [selectedImages]);

  const handleDrag = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === "dragenter" || e.type === "dragover") {
      setDragActive(true);
    } else if (e.type === "dragleave") {
      setDragActive(false);
    }
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
      handleFiles(Array.from(e.dataTransfer.files));
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    e.preventDefault();
    if (e.target.files && e.target.files.length > 0) {
      handleFiles(Array.from(e.target.files));
    }
  };

  const handleFiles = (newFiles: File[]) => {
    const validFiles = newFiles.filter(file => file.type.startsWith('image/'));
    if (validFiles.length === 0) {
      alert("Please upload image files.");
      return;
    }
    onImagesSelect([...selectedImages, ...validFiles]);
  };

  const removeImage = (index: number) => {
    const newFiles = selectedImages.filter((_, i) => i !== index);
    onImagesSelect(newFiles);
    if (newFiles.length === 0) {
        onClear();
    }
  };

  const triggerClick = () => {
    inputRef.current?.click();
  };

  if (selectedImages.length > 0) {
    return (
      <div className="w-full relative flex flex-col justify-between">
        <div className="grid grid-cols-3 gap-2">
            {previews.map((url, idx) => (
                <div key={idx} className="group relative aspect-square rounded-lg overflow-hidden border border-slate-200 hover:border-indigo-400 transition-colors">
                    <img src={url} alt={`preview ${idx}`} className="w-full h-full object-cover" />
                    {!isAnalyzing && (
                        <button 
                            onClick={(e) => { e.stopPropagation(); removeImage(idx); }}
                            className="absolute top-1 right-1 bg-black/50 text-white hover:bg-red-500 p-1 rounded-full opacity-0 group-hover:opacity-100 transition-all"
                        >
                            <X size={10} />
                        </button>
                    )}
                </div>
            ))}

            {!isAnalyzing && (
                <button 
                    onClick={triggerClick}
                    className="aspect-square flex flex-col items-center justify-center bg-slate-50 border border-dashed border-slate-300 rounded-lg hover:bg-white hover:border-indigo-400 transition-all group"
                >
                    <Plus size={16} className="text-slate-400 group-hover:text-indigo-500" />
                </button>
            )}
        </div>

        {!isAnalyzing && (
             <div className="flex justify-between items-center mt-3">
                <span className="text-xs font-semibold text-slate-500">{selectedImages.length} images</span>
                <button 
                    onClick={onClear}
                    className="text-[10px] text-slate-400 hover:text-red-600 transition-colors uppercase font-bold tracking-wider"
                >
                    Clear All
                </button>
             </div>
        )}

        <input ref={inputRef} type="file" className="hidden" onChange={handleChange} accept="image/*" multiple />
      </div>
    );
  }

  return (
    <div 
      className={`relative h-40 flex flex-col items-center justify-center p-4 border-2 border-dashed rounded-xl transition-all duration-300 cursor-pointer overflow-hidden group
        ${dragActive 
            ? "border-indigo-500 bg-indigo-50" 
            : "border-slate-200 hover:border-indigo-300 hover:bg-slate-50"}`}
      onDragEnter={handleDrag}
      onDragLeave={handleDrag}
      onDragOver={handleDrag}
      onDrop={handleDrop}
      onClick={triggerClick}
    >
      <input ref={inputRef} type="file" className="hidden" onChange={handleChange} accept="image/*" multiple />

      <div className="relative z-10 flex flex-col items-center">
          <div className="bg-white p-3 rounded-xl shadow-sm border border-slate-100 mb-3 group-hover:scale-110 transition-transform">
            <UploadCloud size={24} className="text-indigo-600" />
          </div>
          <p className="text-slate-600 text-xs font-semibold">Click to Upload</p>
          <p className="text-slate-400 text-[10px] mt-1">or drag and drop</p>
      </div>
    </div>
  );
};

export default ImageUpload;

