                    subtitle="格式：16:9 横屏 | 场景：品牌故事与氛围" 
                />
                <div className="grid grid-cols-1 gap-4">
                    {data.gemini_rich_content_prompts.map((item, idx) => (
                        <CodeBlock 
                            key={`rich-${idx}`}
                            title={item.title}
                            purpose={item.purpose}
                            code={item.prompt}
                            index={idx}
                        />
                    ))}
                </div>
            </div>
         )}

         {/* Short Video (9:16) */}
         {data.gemini_video_prompts?.length > 0 && (
            <div className="space-y-4">
                <SectionHeader 
                    icon={<Smartphone size={18} />} 
                    title="短视频脚本指令 (Reels)" 
                    subtitle="格式：9:16 竖屏 | 场景：Ozon Moments" 
                />
                <div className="grid grid-cols-1 gap-4">
                    {data.gemini_video_prompts.map((item, idx) => (
                        <CodeBlock 
                            key={`video-${idx}`}
                            title={item.title}
                            purpose={item.purpose}
                            code={item.prompt}
                            index={idx}
                        />
                    ))}
                </div>
            </div>
         )}
      </div>

    </div>
  );
};

// --- Helper Components ---

interface SectionHeaderProps {
    icon: React.ReactNode;
    title: string;
    subtitle: string;
}

const SectionHeader: React.FC<SectionHeaderProps> = ({icon, title, subtitle}) => (
    <div className="flex items-center justify-between mb-2">
        <div className="flex items-center gap-2.5">
            <div className="text-slate-800">{icon}</div>
            <div>
                <h3 className="text-sm font-bold text-slate-900">{title}</h3>
                <p className="text-[10px] text-slate-400 font-medium mt-0.5">{subtitle}</p>
            </div>
        </div>
    </div>
);

interface CodeBlockProps {
    title: string;
    purpose: string;
    code: string;
    index: number;
    highlight?: boolean;
}

const CodeBlock: React.FC<CodeBlockProps> = ({title, purpose, code, index, highlight = false}) => {
    const [copied, setCopied] = React.useState(false);

    const handleCopy = () => {
        navigator.clipboard.writeText(code);
        setCopied(true);
        setTimeout(() => setCopied(false), 2000);
    };

    return (
        <div className={`
            rounded-lg border transition-all duration-200 overflow-hidden
            ${highlight 
                ? 'bg-white border-indigo-200 shadow-sm ring-1 ring-indigo-50' 
                : 'bg-white border-slate-200 hover:border-slate-300'}
        `}>
            {/* Header */}
            <div className="px-4 py-3 bg-slate-50/50 border-b border-slate-100 flex items-center justify-between">
                <div className="flex items-center gap-3">
                    <span className="text-xs font-mono font-bold text-slate-400">#{index + 1}</span>
                    <div>
                        <span className="text-xs font-bold text-slate-800 mr-2">{title}</span>
                        <span className="text-[10px] text-slate-500 bg-slate-100 px-1.5 py-0.5 rounded border border-slate-200">{purpose}</span>
                    </div>
                </div>
                <button 
                    onClick={handleCopy}
                    className={`
                        flex items-center gap-1.5 px-2 py-1 rounded text-[10px] font-bold tracking-wide uppercase transition-colors
                        ${copied 
                            ? 'bg-green-100 text-green-700' 
                            : 'bg-white border border-slate-200 text-slate-600 hover:bg-slate-900 hover:text-white hover:border-slate-900'}
                    `}
                >
                    {copied ? <Check size={12} /> : <Copy size={12} />}
                    {copied ? 'Copied' : 'Copy Prompt'}
                </button>
            </div>

            {/* Code Content */}
            <div className="p-4 bg-white relative">
                <pre className="text-xs text-slate-600 font-mono whitespace-pre-wrap leading-relaxed">
                    {code}
                </pre>
            </div>
        </div>
    );
}

export default AnalysisResult;
